{
  "name": "lambda-forks-ts",
  "version": "0.1.0",
  "private": true,
  "type": "commonjs",
  "scripts": {
    "build": "node ./node_modules/typescript/bin/tsc -p tsconfig.json",
    "test": "npm run build --silent && node dist/test/smoke.js",
    "forks-ts": "npm run build --silent && node dist/src/cli.js"
  },
  "devDependencies": {
    "@types/node": "^24.0.0",
    "typescript": "^5.8.0"
  }
}

import { spawnSync } from 'node:child_process';

export interface InvocationPlan {
  corePath: string;
  coreArgs: string[];
}

export function usage(): string {
  return [
    'Usage:',
    '  forks-ts [--core-path <forks-core>] status [args...]',
    '  forks-ts [--core-path <forks-core>] audit --gadget <gizmo> <gadget>',
    '',
    'This wrapper is intentionally thin. It validates operator-facing shape,',
    'then delegates deterministic filesystem, git, ledger, and audit mechanics',
    'to forks-core.'
  ].join('\n');
}

export function planInvocation(args: string[], envCorePath = process.env.FORKS_CORE ?? 'forks-core'): InvocationPlan {
  const rest = [...args];
  let corePath = envCorePath;
  if (rest[0] === '--core-path') {
    const configured = rest[1];
    if (!configured) throw new Error('missing value for --core-path');
    corePath = configured;
    rest.splice(0, 2);
  }
  const command = rest[0];
  if (!command) throw new Error('missing command');
  if (command !== 'status' && command !== 'audit') {
    throw new Error(`unsupported forks-ts command in read-only scaffold: ${command}`);
  }
  if (command === 'audit') {
    const gadgetIdx = rest.indexOf('--gadget');
    if (gadgetIdx === -1 || !rest[gadgetIdx + 1] || !rest[gadgetIdx + 2]) {
      throw new Error('audit requires --gadget <gizmo> <gadget>');
    }
  }
  return { corePath, coreArgs: rest };
}

export function runForksTs(args = process.argv.slice(2)): number {
  let plan: InvocationPlan;
  try {
    plan = planInvocation(args);
  } catch (err) {
    console.error(err instanceof Error ? err.message : String(err));
    console.error(usage());
    return 1;
  }

  const result = spawnSync(plan.corePath, plan.coreArgs, {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  if (result.error) {
    console.error(`failed to run forks-core at ${plan.corePath}: ${result.error.message}`);
    return 1;
  }
  if (result.stdout) process.stdout.write(result.stdout);
  if (result.stderr) process.stderr.write(result.stderr);
  return result.status ?? 1;
}

if (require.main === module) {
  process.exit(runForksTs());
}

import assert from 'node:assert/strict';
import { planInvocation } from '../src/cli';

const status = planInvocation(['--core-path', 'C:/tools/forks-core.exe', 'status']);
assert.strictEqual(status.corePath, 'C:/tools/forks-core.exe');
assert.deepStrictEqual(status.coreArgs, ['status']);

const audit = planInvocation(['audit', '--gadget', 'lambdascript', 'core'], 'forks-core-test');
assert.strictEqual(audit.corePath, 'forks-core-test');
assert.deepStrictEqual(audit.coreArgs, ['audit', '--gadget', 'lambdascript', 'core']);

assert.throws(
  () => planInvocation(['agent-land']),
  /unsupported forks-ts command in read-only scaffold: agent-land/,
  'read-only wrapper should reject mutating commands at this stage',
);

assert.throws(
  () => planInvocation(['audit', '--gadget', 'lambdascript']),
  /audit requires --gadget <gizmo> <gadget>/,
  'audit should require complete gadget identity',
);

console.log('forks-ts read-only scaffold smoke passed');

